    },
    {
      "path": "src/App.tsx",
      "content": "import { useMemo, useState } from 'react';

type Page = 'overview' | 'routing' | 'report';

const metrics = [
  { label: 'Pass rate', value: '96.4%', trend: '+1.8%' },
  { label: 'Latency', value: '182 ms', trend: '-24 ms' },
  { label: 'Cost / 1k', value: '$0.18', trend: '-12%' },
  { label: 'Alpha / Beta', value: '0.72 / 0.28', trend: 'Stable' }
];

const candidates = [
  { name: 'gpt-5.3-codex', score: '0.94', role: 'Primary reasoning' },
  { name: 'gpt-5.4-mini', score: '0.89', role: 'Fast fallback' },
  { name: 'gpt-5.4-nano', score: '0.81', role: 'Low-cost router' }
];

export default function App() {
  const [page, setPage] = useState<Page>('overview');
  const activeTitle = useMemo(() => {
    if (page === 'routing') return 'Routing Lab';
    if (page === 'report') return 'Eval Report';
    return 'Overview';
  }, [page]);

  return (
    <div className="app-shell">
      <aside className="sidebar">
        <div>
          <div className="brand-badge">Agent Sam</div>
          <h1>Command Center</h1>
          <p className="sidebar-copy">Thompson routing, evals, and model ops in one control surface.</p>
        </div>

        <nav className="nav">
          <button className={page === 'overview' ? 'nav-btn active' : 'nav-btn'} onClick={() => setPage('overview')}>Overview</button>
          <button className={page === 'routing' ? 'nav-btn active' : 'nav-btn'} onClick={() => setPage('routing')}>Routing Lab</button>
          <button className={page === 'report' ? 'nav-btn active' : 'nav-btn'} onClick={() => setPage('report')}>Eval Report</button>
        </nav>

        <div className="sidebar-foot">
          <span className="status-dot" /> Live mock telemetry
        </div>
      </aside>

      <main className="main">
        <header className="topbar">
          <div>
            <p className="eyebrow">Agent Sam Command Center</p>
            <h2>{activeTitle}</h2>
          </div>
          <div className="topbar-chip">npm run build ready</div>
        </header>

        {page === 'overview' && (
          <section className="page-grid">
            <section className="hero card gradient">
              <div>
                <p className="eyebrow">Thompson routing</p>
                <h3>Confident model selection with crisp observability.</h3>
                <p>
                  Track pass rate, latency, cost, and alpha/beta routing decisions across the Agent Sam stack.
                </p>
              </div>
              <div className="hero-panel">
                <div className="ring">96.4%</div>
                <div>
                  <div className="mini-label">Top candidate</div>
                  <strong>gpt-5.3-codex</strong>
                </div>
              </div>
            </section>

            <section className="metrics-row">
              {metrics.map((m) => (
                <article className="card metric-card" key={m.label}>
                  <span>{m.label}</span>
                  <strong>{m.value}</strong>
                  <small>{m.trend}</small>
                </article>
              ))}
            </section>

            <section className="card content-card">
              <h4>Candidate pool</h4>
              <div className="candidate-list">
                {candidates.map((c) => (
                  <div className="candidate-row" key={c.name}>
                    <div>
                      <strong>{c.name}</strong>
                      <p>{c.role}</p>
                    </div>
                    <span>{c.score}</span>
                  </div>
                ))}
              </div>
            </section>
          </section>
        )}

        {page === 'routing' && (
          <section className="page-grid two-col">
            <article className="card content-card">
              <h4>Routing controls</h4>
              <div className="stack">
                <div className="pill-row">
                  <span className="pill active">alpha = 0.72</span>
                  <span className="pill">beta = 0.28</span>
                  <span className="pill">guardrail: on</span>
                </div>
                <div className="lab-box">
                  <p className="eyebrow">Decision snapshot</p>
                  <h3>Route complex prompts to gpt-5.3-codex, cheap requests to gpt-5.4-nano.</h3>
                  <p>gpt-5.4-mini remains the fallback for balanced speed and quality.</p>
                </div>
              </div>
            </article>

            <article className="card content-card">
              <h4>Live ladder</h4>
              <div className="ladder">
                <div><span>gpt-5.3-codex</span><em>0.94</em></div>
                <div><span>gpt-5.4-mini</span><em>0.89</em></div>
                <div><span>gpt-5.4-nano</span><em>0.81</em></div>
              </div>
            </article>
          </section>
        )}

        {page === 'report' && (
          <section className="page-grid">
            <article className="card content-card report-card">
              <h4>Eval summary</h4>
              <div className="report-grid">
                <div><span>Pass rate</span><strong>96.4%</strong></div>
                <div><span>Latency p95</span><strong>244 ms</strong></div>
                <div><span>Cost delta</span><strong>-12%</strong></div>
                <div><span>Routing drift</span><strong>0.03</strong></div>
              </div>
            </article>
            <article className="card content-card">
              <h4>Notes</h4>
              <ul className="notes-list">
                <li>gpt-5.3-codex leads accuracy-sensitive traffic.</li>
                <li>gpt-5.4-mini is consistent under burst load.</li>
                <li>gpt-5.4-nano preserves budget on short tasks.</li>
              </ul>
            </article>
          </section>
        )}
      </main>
    </div>
  );
}
"
    },
    {
      "path": "src/App.css",
      "content": ":root {
  font-family: Inter, system-ui, -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;
  color: #e8ecff;
  background: radial-gradient(circle at top, #1d2b5a 0%, #0b1020 45%, #070b14 100%);
  line-height: 1.5;
  font-weight: 400;
}

* { box-sizing: border-box; }
body { margin: 0; min-width: 320px; background: transparent; }
button { font: inherit; }

.app-shell {
  min-height: 100vh;
  display: grid;
  grid-template-columns: 280px 1fr;
}

.sidebar {
  padding: 28px;
  background: rgba(7, 11, 20, 0.72);
  border-right: 1px solid rgba(255,255,255,0.08);
  backdrop-filter: blur(18px);
  display: flex;
  flex-direction: column;
  justify-content: space-between;
}

.brand-badge, .topbar-chip, .pill, .status-dot, .metric-card, .card { border-radius: 18px; }
.brand-badge {
  width: fit-content;
  padding: 8px 12px;
  background: linear-gradient(135deg, #7c5cff, #33d6ff);
  color: white;
  font-weight: 700;
}
.sidebar h1, .topbar h2, .hero h3, .content-card h4 { margin: 0; }
.sidebar-copy, .hero p, .lab-box p, .notes-list { color: rgba(232,236,255,0.78); }
.nav { display: grid; gap: 10px; margin: 28px 0; }
.nav-btn {
  border: 1px solid rgba(255,255,255,0.1);
  background: rgba(255,255,255,0.04);
  color: #e8ecff;
  padding: 12px 14px;
  text-align: left;
  cursor: pointer;
}
.nav-btn.active { background: linear-gradient(135deg, rgba(124,92,255,0.35), rgba(51,214,255,0.22)); }
.sidebar-foot { display: flex; gap: 10px; align-items: center; color: rgba(232,236,255,0.7); }
.status-dot { width: 10px; height: 10px; background: #40f0a5; box-shadow: 0 0 18px #40f0a5; }

.main { padding: 28px; }
.topbar { display: flex; justify-content: space-between; align-items: center; margin-bottom: 22px; }
.eyebrow { text-transform: uppercase; letter-spacing: 0.16em; font-size: 0.72rem; color: #8fb6ff; margin: 0 0 6px; }
.topbar-chip { padding: 10px 14px; background: rgba(255,255,255,0.08); }
.page-grid { display: grid; gap: 18px; }
.two-col { grid-template-columns: 1.2fr 0.8fr; }
.card {
  padding: 22px;
  background: rgba(10, 16, 32, 0.72);
  border: 1px solid rgba(255,255,255,0.08);
  box-shadow: 0 18px 60px rgba(0,0,0,0.28);
}
.gradient { background: linear-gradient(135deg, rgba(124,92,255,0.28), rgba(51,214,255,0.12)); }
.hero { display: flex; justify-content: space-between; gap: 20px; align-items: center; }
.hero-panel { display: grid; gap: 12px; justify-items: center; min-width: 180px; }
.ring {
  width: 120px; height: 120px; border-radius: 50%; display: grid; place-items: center;
  background: conic-gradient(#33d6ff 0 96%, rgba(255,255,255,0.15) 96% 100%);
  color: #06111f; font-weight: 800; font-size: 1.4rem;
}
.metrics-row { display: grid; grid-template-columns: repeat(4, 1fr); gap: 18px; }
.metric-card span, .candidate-row p, .report-grid span { color: rgba(232,236,255,0.7); }
.metric-card strong, .candidate-row span, .report-grid strong { font-size: 1.5rem; display: block; margin-top: 8px; }
.content-card { display: grid; gap: 16px; }
.candidate-list, .ladder, .report-grid { display: grid; gap: 12px; }
.candidate-row, .ladder div, .report-grid div {
  display: flex; justify-content: space-between; align-items: center;
  padding: 14px 16px; background: rgba(255,255,255,0.04); border-radius: 14px;
}
.pill-row { display: flex; gap: 10px; flex-wrap: wrap; }
.pill { padding: 8px 12px; background: rgba(255,255,255,0.06); }
.pill.active { background: rgba(64,240,165,0.15); color: #c9ffe9; }
.lab-box { padding: 18px; border-radius: 16px; background: rgba(255,255,255,0.04); }
.notes-list { margin: 0; padding-left: 18px; }
.stack { display: grid; gap: 16px; }

@media (max-width: 900px) {
  .app-shell { grid-template-columns: 1fr; }
  .sidebar { border-right: 0; border-bottom: 1px solid rgba(255,255,255,0.08); }
  .metrics-row, .two-col { grid-template-columns: 1fr; }
  .hero { flex-direction: column; align-items: flex-start; }
  .topbar { flex-direction: column; align-items: flex-start; gap: 12px; }
}
